const trigger = $('When Executed by Another Workflow').first().json || {};
const pedido = $('Obtener Pedido Activo').first().json || {};
const zona = $('Consultar Zona Delivery').first().json || {};

function money(v) {
  return '€' + Number(v || 0).toFixed(2).replace('.', ',');
}

const subtotal = Number(pedido.subtotal || 0);
const minimo = Number(zona.min_order_amount || 0);
const fee = Number(zona.fee || 0);
const total = subtotal + fee;

const base = {
  pedido_id: pedido.id,
  pedido_numero: pedido.pedido_numero,
  pedido_codigo: pedido.pedido_codigo || null,
  tipo_despacho: 'delivery',
  direccion: trigger.direccion_texto || pedido.direccion || '',
  codigo_postal: trigger.codigo_postal || zona.postal_code || '',
  lat: (trigger.lat !== '' && trigger.lat != null) ? Number(trigger.lat) : (pedido.lat ?? null),
  lng: (trigger.lng !== '' && trigger.lng != null) ? Number(trigger.lng) : (pedido.lng ?? null),
  zona_nombre: zona.zone_name || null,
  fee,
  subtotal,
  total,
  tiempo_min: zona.estimated_minutes_min,
  tiempo_max: zona.estimated_minutes_max,
  telefono: trigger.telefono,
  session_id: trigger.session_id
};

if (subtotal < minimo) {
  return [{
    json: {
      ...base,
      puede_continuar: false,
      motivo: 'minimo_no_alcanzado',
      delivery_pendiente_minimo: true,
      respuesta_agente: `Mantengo delivery a ${base.direccion}. Tu pedido es de ${money(subtotal)} y el mínimo para esa zona es ${money(minimo)}. ¿Quieres agregar algo más para llegar al mínimo o prefieres pasar a retiro?`
    }
  }];
}

return [{
  json: {
    ...base,
    puede_continuar: true,
    delivery_pendiente_minimo: false
  }
}];

const trigger = $('When Executed by Another Workflow').first().json || {};
const pedido = $('Obtener Pedido Activo').first().json || {};

return [{
  json: {
    pedido_id: pedido.id,
    pedido_numero: pedido.pedido_numero,
    pedido_codigo: pedido.pedido_codigo || null,
    tipo_despacho: 'retiro',
    fee: 0,
    subtotal: Number(pedido.subtotal || 0),
    total: Number(pedido.subtotal || 0),
    telefono: trigger.telefono,
    session_id: trigger.session_id
  }
}];

const pedidoDB = $json || {};
const subtotal = Number(pedidoDB.subtotal || 0);
const tiempo = pedidoDB.tiempo_estimado || '20 min';

function money(v) {
  return '€' + Number(v || 0).toFixed(2).replace('.', ',');
}

// Finding 4: list available payment methods dynamically
const db = pedidoDB.datos_bancarios || null;
let opcionesPago = 'efectivo';
if (db) opcionesPago += ' o transferencia bancaria';

return [{
  json: {
    success: true,
    tipo_despacho: 'retiro',
    respuesta_agente: `Perfecto, tu pedido${pedidoDB.pedido_codigo ? ` ${pedidoDB.pedido_codigo}` : ''} será para retiro en el local. Tiempo estimado: ${tiempo}. El subtotal es ${money(subtotal)}. ¿Cómo quieres pagar? Puedes pagar en ${opcionesPago}.`,
    pedido_id: pedidoDB.id,
    pedido_numero: pedidoDB.pedido_numero,
    pedido_codigo: pedidoDB.pedido_codigo || null,
    subtotal,
    costo_envio: 0,
    total: subtotal,
    tiempo_estimado: tiempo
  }
}];

const pedidoDB = $json || {};
const fee = Number(pedidoDB.costo_envio || 0);
const subtotal = Number(pedidoDB.subtotal || 0);
const total = Number(pedidoDB.total || 0);
const tiempo = pedidoDB.tiempo_estimado || '30-45 min';

function money(v) {
  return '€' + Number(v || 0).toFixed(2).replace('.', ',');
}

// Finding 4: list available payment methods dynamically
const db = pedidoDB.datos_bancarios || null;
let opcionesPago = 'efectivo';
if (db) opcionesPago += ' o transferencia bancaria';

return [{
  json: {
    success: true,
    tipo_despacho: 'delivery',
    respuesta_agente: `Perfecto, mantengo delivery${pedidoDB.direccion ? ` a ${pedidoDB.direccion}` : ''}. El envío tiene un costo de ${money(fee)} y el tiempo estimado es ${tiempo}. El total con despacho es ${money(total)}. ¿Cómo quieres pagar? Puedes pagar en ${opcionesPago}.`,
    pedido_id: pedidoDB.id,
    pedido_numero: pedidoDB.pedido_numero,
    pedido_codigo: pedidoDB.pedido_codigo || null,
    subtotal,
    costo_envio: fee,
    total,
    direccion: pedidoDB.direccion,
    tiempo_estimado: tiempo
  }
}];

const trigger = $('When Executed by Another Workflow').first().json || {};
const pedido = $('Obtener Pedido Activo').first().json || {};

const address  = String(trigger.direccion_texto || '').trim();
const cp       = String(trigger.codigo_postal   || '').trim();
const hasAddress = address.length > 0 || cp.length > 0;

const ZONAS_DISPONIBLES = ['Arrecife', 'Playa Honda', 'Taiche'];
const zonasList = ZONAS_DISPONIBLES.join(', ');

// Detectar si el texto de la dirección ya menciona zona o CP de 5 dígitos
const addressLower = (address + ' ' + cp).toLowerCase();
const hasZoneHint  = ZONAS_DISPONIBLES.some(z => addressLower.includes(z.toLowerCase()))
                   || /\b\d{5}\b/.test(address + ' ' + cp);

let respuesta;
let motivo;

if (!hasAddress) {
  motivo    = 'sin_direccion';
  respuesta = `Para delivery necesito tu dirección completa con zona o CP. `
            + `Zonas disponibles: ${zonasList}. `
            + `¿A qué dirección te lo enviamos? Ej: Calle Mayor 12, 3ºA, Arrecife.`;
} else if (!hasZoneHint) {
  motivo    = 'zona_no_identificada';
  respuesta = `Recibí la dirección "${address}", pero necesito saber en qué zona está para calcular el envío. `
            + `¿Es Arrecife, Playa Honda o Taiche?`;
} else {
  motivo    = 'fuera_de_cobertura';
  respuesta = `Lo siento, no llegamos a "${address || cp}". `
            + `Nuestras zonas de delivery son: ${zonasList}. `
            + `¿Quieres cambiar la dirección o prefieres retiro en el local?`;
}

return [{
  json: {
    success: false,
    motivo,
    respuesta_agente: respuesta,
    pedido_id:     pedido.id,
    pedido_numero: pedido.pedido_numero,
    pedido_codigo: pedido.pedido_codigo || null,
    subtotal:      Number(pedido.subtotal || 0)
  }
}];

const pedidoDB = $json || {};
const trigger = $('When Executed by Another Workflow').first().json || {};
const zona = $('Consultar Zona Delivery').first().json || {};

function money(v) {
  return '€' + Number(v || 0).toFixed(2).replace('.', ',');
}

const subtotal = Number(pedidoDB.subtotal || 0);
const fee = Number(pedidoDB.costo_envio || 0);
const minimo = Number(zona.min_order_amount || 0);
const totalEstimado = subtotal + fee;
const tiempo = pedidoDB.tiempo_estimado || '30-45 min';

return [{
  json: {
    success: false,
    motivo: 'minimo_no_alcanzado',
    tipo_despacho: 'delivery',
    respuesta_agente: `Mantengo delivery${pedidoDB.direccion ? ` a ${pedidoDB.direccion}` : ''}. Tu pedido va en ${money(subtotal)} y el mínimo para esa zona es ${money(minimo)}. Si llegas al mínimo, el total estimado con envío será ${money(totalEstimado)} y el tiempo estimado será ${tiempo}. ¿Quieres agregar algo más o prefieres pasar a retiro?`,
    pedido_id: pedidoDB.id,
    pedido_numero: pedidoDB.pedido_numero,
    pedido_codigo: pedidoDB.pedido_codigo || null,
    subtotal,
    costo_envio: fee,
    total_estimado: totalEstimado,
    direccion: pedidoDB.direccion || trigger.direccion_texto || null,
    tiempo_estimado: tiempo
  }
}];

// Nodo de catch global para Despacho
// Se activa cuando cualquier nodo upstream falla (onError: continueErrorOutput)
const err = $input.first();
const origen = err?.json?.node || err?.json?.source || 'nodo desconocido';
const detalle = err?.json?.message || err?.json?.error || 'sin detalle';
const telefono = $('When Executed by Another Workflow').first().json?.telefono || '';

return [{
  json: {
    success: false,
    error: true,
    tipo: 'sistema',
    subflujo: 'Despacho',
    mensaje: `Error técnico en Despacho (${origen}): ${detalle}`,
    puede_continuar: false,
    mutar_db: false,
    telefono: telefono,
    problema_escalacion: `Error técnico en Despacho (${origen}): ${detalle}`
  }
}];
